    input.set_mouse_mode(Input.MOUSE_MODE_CAPTURE)
    input.set_visible(true)
    input.set_lock_cursor(true)
    set_process(true)

func _process(delta: float) -> void:
    # Get user input and update movement variables
    get_user_input(delta)

    # Apply movement variables to velocity and apply gravity
    velocity.x += velocity.x * air_acceleration * delta
    if (is_moving || ground_check) and not is_jumping:
        velocity.y += gravity * delta

