            velocity.y -= jump_strength * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta * delta
        KinematicBody.set_linear(velocity)

    # Update position based on velocity and set ground check flag for next frame
    transform.origin += velocity.normalized()*(ground_speed*delta) + Vector3(0,ground_check?-1:1,0)
    ground_check = false

