    # Calculate last update time for input debounce mechanism
    last_update = get_tree().get_timestep() + last_update % 1;

    # Update input debounce mechanism to avoid spamming actions in quick succession
    func debounce(action: String): bool:
        return !input[action] and not input[action..".."] and (get_tree().get_timestep() + last_update - 1) % 1 >= 0.2; # Debounce time is 200ms (0.2 seconds)

    func get_ground(): KinematicBody2D | null:
        return get_node("/root/Ground")?.get("KinematicBody") as KinematicBody2D | null; # Find the Ground KinematicBody node and return it as a KinematicBody2D object or null if not found

    func get_user_input(_delta: float): void: # Get user input based on mouse and keyboard actions, debounce input events, and store input variables for movement calculations later in _process() function
        var x = debounce("ui_left") - debounce("ui_right") # Left and right arrow key or mouse left/right movement input (-1 to 1 values)
        var y = debounce("ui_up") - debounce("ui_down") # Up and down arrow key or mouse scroll wheel movement input (-1 to 1 values) # Note that "ui" prefix is used for user interface actions instead of "input" prefix, as "input" prefix is reserved for system input events like mouse buttons and keyboard keys. This is because user interface actions are specific to the game's UI implementation, while system input events are more generic and should be handled separately by the OS or engine itself. Also note that debounce() function is used to prevent spamming of actions in quick succession, which can cause unwanted behavior in some cases, especially when dealing with high frame rates or multiple simultaneous inputs from different devices or sources (e.g., keyboard, mouse, touch screen). This function checks if an action has been released for at least 200ms (0.2 seconds) before considering it as a valid input event, which helps to avoid false positives and reduce noise in the input stream, making the game more responsive and predictable for the player. The last update time is also stored in a global variable (last_update) to avoid redundant calculations in each frame and improve performance. The debounce function can be customized according to the specific needs of the game's UI design and input handling requirements, by adjusting the debounce time and other parameters like action names, debounce duration, etc.
